    32→
    33→  function nearestPollInterval(seconds: number): string {
    34→    const values = POLL_INTERVAL_OPTIONS.map((o) => Number(o.value));
    35→    let closest = values[0];
    36→    for (const v of values) {
    37→      if (Math.abs(v - seconds) < Math.abs(closest - seconds)) closest = v;
    38→    }
    39→    return String(closest);
    40→  }
