   205→      <div className="flex justify-end gap-2">
   206→        <Button type="button" variant="outline" onClick={handleCancel}>Cancel</Button>
   207→        <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   208→      </div>
   209→    </form>
   210→  );
   211→
   212→  // Dialog mode: return form content without Card wrapper
   213→  if (onSuccess) {
   214→    return formContent;
   215→  }
   216→
   217→  // Page mode: wrap in Card
   218→  return (
   219→    <Card className="mx-auto max-w-2xl">
   220→      <CardHeader>
   221→        <CardTitle>{title}</CardTitle>
   222→      </CardHeader>
   223→      <CardContent>
   224→        {formContent}
   225→      </CardContent>
   226→    </Card>
   227→  );
   228→}
