export function timeAgo(dateStr?: string | null): string {
  if (!dateStr) return "\u2014";
  const diff = Date.now() - new Date(dateStr).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

export function validateRepository(provider: string, repo: string): string | null {
  const trimmed = repo.trim();
  if (!trimmed) return null;
  if (provider === "github" && /^(https?:\/\/)?github\.com\//i.test(trimmed)) {
    return "Use owner/repo format (e.g. ethereum/go-ethereum), not a full URL";
  }
  if (provider === "dockerhub" && /^(https?:\/\/)?hub\.docker\.com\//i.test(trimmed)) {
    return "Use owner/image format (e.g. library/nginx), not a full URL";
  }
  if (provider === "ecr-public" && /^(https?:\/\/)?(gallery\.ecr\.aws|public\.ecr\.aws)\//i.test(trimmed)) {
    return "Use alias/repo format (e.g. i6b2w2n6/op-node), not a full URL";
  }
  if (provider === "gitlab" && /^(https?:\/\/)?gitlab\.com\//i.test(trimmed)) {
    return "Use owner/repo format (e.g. inkscape/inkscape), not a full URL";
  }
  if (/^https?:\/\//.test(trimmed)) {
    return "Use owner/repo format, not a full URL";
  }
  return null;
}

export function formatInterval(seconds: number): string {
  if (seconds === 3600) return "Hourly";
  if (seconds === 86400) return "Daily";
  if (seconds === 604800) return "Weekly";
  if (seconds === 2592000) return "Monthly";
  if (seconds < 60) return `${seconds}s`;
  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
  if (seconds < 86400) return `${(seconds / 3600).toFixed(1)}h`;
  return `${(seconds / 86400).toFixed(1)}d`;
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import type { Source, SourceInput } from "@/lib/api/types";
import { validateRepository } from "@/lib/format";

interface SourceFormProps {
  initial?: Source;
  projectId?: string;
  onSubmit: (input: SourceInput) => Promise<void>;
  title: string;
  redirectTo?: string;
  onSuccess?: () => void;
  onCancel?: () => void;
}


const POLL_INTERVAL_OPTIONS = [
    { label: "Hourly", value: "3600" },
    { label: "Daily", value: "86400" },
    { label: "Weekly", value: "604800" },
    { label: "Monthly", value: "2592000" },
  ];

  function nearestPollInterval(seconds: number): string {
    const values = POLL_INTERVAL_OPTIONS.map((o) => Number(o.value));
    let closest = values[0];
    for (const v of values) {
      if (Math.abs(v - seconds) < Math.abs(closest - seconds)) closest = v;
    }
    return String(closest);
  }


export function SourceForm({ initial, onSubmit, title, redirectTo, onSuccess, onCancel }: SourceFormProps) {
  const router = useRouter();
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [provider, setProvider] = useState(initial?.provider ?? "dockerhub");
  const [repository, setRepository] = useState(initial?.repository ?? "");
  const [pollInterval, setPollInterval] = useState(
    nearestPollInterval(initial?.poll_interval_seconds ?? 86400)
  );
  const [enabled, setEnabled] = useState(initial?.enabled ?? true);
  const [configJson, setConfigJson] = useState(
    JSON.stringify(initial?.config ?? {}, null, 2)
  );
  const [versionFilterInclude, setVersionFilterInclude] = useState(initial?.version_filter_include ?? "");
  const [versionFilterExclude, setVersionFilterExclude] = useState(initial?.version_filter_exclude ?? "");
  const [excludePrereleases, setExcludePrereleases] = useState(initial?.exclude_prereleases ?? false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");

    const repoError = validateRepository(provider, repository);
    if (repoError) {
      setError(repoError);
      return;
    }

    let parsedConfig: Record<string, unknown> | undefined;
    if (configJson.trim() && configJson.trim() !== "{}") {
      try {
        parsedConfig = JSON.parse(configJson);
      } catch {
        setError("Config must be valid JSON");
        return;
      }
    }

    setSaving(true);
    try {
      await onSubmit({
        provider,
        repository: repository.trim(),
        poll_interval_seconds: Number(pollInterval),
        enabled,
        config: parsedConfig,
        version_filter_include: versionFilterInclude.trim() || undefined,
        version_filter_exclude: versionFilterExclude.trim() || undefined,
        exclude_prereleases: excludePrereleases || undefined,
      });
      if (onSuccess) {
        onSuccess();
      } else {
        router.push(redirectTo ?? "/sources");
      }
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to save");
    } finally {
      setSaving(false);
    }
  };

  const handleCancel = () => {
    if (onCancel) {
      onCancel();
    } else {
      router.back();
    }
  };

  const formContent = (
    <form onSubmit={handleSubmit} className="space-y-4">
      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
      <div className="space-y-2">
        <Label>Provider</Label>
        <Select value={provider} onValueChange={setProvider}>
          <SelectTrigger><SelectValue /></SelectTrigger>
          <SelectContent>
            <SelectItem value="dockerhub">Docker Hub</SelectItem>
            <SelectItem value="github">GitHub</SelectItem>
            <SelectItem value="ecr-public">ECR Public</SelectItem>
            <SelectItem value="gitlab">GitLab</SelectItem>
            <SelectItem value="pypi">PyPI</SelectItem>
          </SelectContent>
        </Select>
      </div>
      <div className="space-y-2">
        <Label htmlFor="repository">Repository</Label>
        <Input id="repository" value={repository} onChange={(e) => setRepository(e.target.value)} placeholder="e.g. library/golang or ethereum/go-ethereum" required />
      </div>
      <div className="space-y-2">
        <Label>Poll Interval</Label>
        <Select value={pollInterval} onValueChange={setPollInterval}>
          <SelectTrigger><SelectValue /></SelectTrigger>
          <SelectContent>
            {POLL_INTERVAL_OPTIONS.map((opt) => (
              <SelectItem key={opt.value} value={opt.value}>{opt.label}</SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>
      <div className="space-y-2">
        <Label htmlFor="config">Config (JSON, optional)</Label>
        <Textarea
          id="config"
          value={configJson}
          onChange={(e) => setConfigJson(e.target.value)}
          rows={4}
          className="font-mono text-sm"
          placeholder="{}"
        />
      </div>
      <div className="space-y-2">
        <Label htmlFor="version_filter_include">Version Filter — Include (regex, optional)</Label>
        <Input
          id="version_filter_include"
          value={versionFilterInclude}
          onChange={(e) => setVersionFilterInclude(e.target.value)}
          placeholder='e.g. ^v\d+\.\d+\.\d+$'
          className="font-mono text-sm"
        />
        <p className="text-xs text-muted-foreground">Only show/notify versions matching this pattern</p>
      </div>
      <div className="space-y-2">
        <Label htmlFor="version_filter_exclude">Version Filter — Exclude (regex, optional)</Label>
        <Input
          id="version_filter_exclude"
          value={versionFilterExclude}
          onChange={(e) => setVersionFilterExclude(e.target.value)}
          placeholder='e.g. -(alpha|beta|rc|nightly)'
          className="font-mono text-sm"
        />
        <p className="text-xs text-muted-foreground">Hide/suppress versions matching this pattern</p>
      </div>
      {(provider === "github" || provider === "gitlab") && (
        <div className="flex items-center gap-3">
          <Switch checked={excludePrereleases} onCheckedChange={setExcludePrereleases} />
          <Label>Exclude Pre-Releases</Label>
        </div>
      )}
      <div className="flex items-center gap-3">
        <Switch checked={enabled} onCheckedChange={setEnabled} />
        <Label>Enabled</Label>
      </div>
      <div className="flex justify-end gap-2">
        <Button type="button" variant="outline" onClick={handleCancel}>Cancel</Button>
        <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
      </div>
    </form>
  );

  if (onSuccess) {
    return formContent;
  }

  return (
    <Card className="mx-auto max-w-2xl">
      <CardHeader><CardTitle>{title}</CardTitle></CardHeader>
      <CardContent>
        {formContent}
      </CardContent>
    </Card>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import type { Project, ProjectInput, SourceInput } from "@/lib/api/types";
import { validateRepository } from "@/lib/format";
import { Plus, X } from "lucide-react";

export interface ProjectFormResult {
  project: ProjectInput;
  source?: SourceInput;
}

interface ProjectFormProps {
  initial?: Project;
  onSubmit: (result: ProjectFormResult) => Promise<void>;
  title: string;
  /** Hide the source section (used in edit mode) */
  hideSource?: boolean;
  /** Dialog mode: called after successful submit instead of router.push */
  onSuccess?: () => void;
  /** Dialog mode: called on cancel instead of router.back */
  onCancel?: () => void;
}

export function ProjectForm({ initial, onSubmit, title, hideSource, onSuccess, onCancel }: ProjectFormProps) {
  const router = useRouter();
  const [saving, setSaving] = useState(false);
  const [name, setName] = useState(initial?.name ?? "");
  const [description, setDescription] = useState(initial?.description ?? "");
  const [error, setError] = useState("");

  /* Source fields (only for create) */
  const [showSource, setShowSource] = useState(false);
  const [provider, setProvider] = useState("github");
  const [repository, setRepository] = useState("");
  const [pollInterval, setPollInterval] = useState("86400");
  const [versionFilterInclude, setVersionFilterInclude] = useState("");
  const [versionFilterExclude, setVersionFilterExclude] = useState("");
  const [excludePrereleases, setExcludePrereleases] = useState(false);

  const handleCancel = () => {
    if (onCancel) {
      onCancel();
    } else {
      router.back();
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSaving(true);
    try {
      const result: ProjectFormResult = {
        project: {
          name,
          description: description || undefined,
        },
      };
      if (showSource && repository.trim()) {
        const repoError = validateRepository(provider, repository.trim());
        if (repoError) {
          setError(repoError);
          setSaving(false);
          return;
        }
        result.source = {
          provider,
          repository: repository.trim(),
          poll_interval_seconds: Number(pollInterval) || 86400,
          enabled: true,
          version_filter_include: versionFilterInclude.trim() || undefined,
          version_filter_exclude: versionFilterExclude.trim() || undefined,
          exclude_prereleases: excludePrereleases || undefined,
        };
      }
      await onSubmit(result);
      if (onSuccess) {
        onSuccess();
      } else {
        router.push("/projects");
      }
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to save");
    } finally {
      setSaving(false);
    }
  };

  const formContent = (
    <form onSubmit={handleSubmit} className="space-y-4">
      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
      <div className="space-y-2">
        <Label htmlFor="name">Name</Label>
        <Input id="name" value={name} onChange={(e) => setName(e.target.value)} required />
      </div>
      <div className="space-y-2">
        <Label htmlFor="description">Description</Label>
        <Textarea id="description" value={description} onChange={(e) => setDescription(e.target.value)} rows={2} />
      </div>

      {/* Optional source section — only in create mode */}
      {!hideSource && (
        <div className="space-y-3">
          {!showSource ? (
            <button
              type="button"
              onClick={() => setShowSource(true)}
              className="inline-flex items-center gap-1.5 text-[13px] font-medium transition-colors hover:opacity-80"
              style={{ color: "#e8601a" }}
            >
              <Plus className="h-3.5 w-3.5" />
              Add a Source
            </button>
          ) : (
            <div className="rounded-md border p-4 space-y-3" style={{ borderColor: "#e8e8e5" }}>
              <div className="flex items-center justify-between">
                <Label className="text-[13px] font-medium">Add a Source</Label>
                <button
                  type="button"
                  onClick={() => { setShowSource(false); setRepository(""); }}
                  className="text-[#9ca3af] hover:text-[#6b7280]"
                >
                  <X className="h-4 w-4" />
                </button>
              </div>
              <div className="space-y-2">
                <Label>Provider</Label>
                <Select value={provider} onValueChange={setProvider}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="github">GitHub</SelectItem>
                    <SelectItem value="dockerhub">Docker Hub</SelectItem>
                    <SelectItem value="ecr-public">ECR Public</SelectItem>
                    <SelectItem value="gitlab">GitLab</SelectItem>
                    <SelectItem value="pypi">PyPI</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label htmlFor="repository">Repository</Label>
                <Input
                  id="repository"
                  value={repository}
                  onChange={(e) => setRepository(e.target.value)}
                  placeholder="e.g. ethereum/go-ethereum"
                />
              </div>
              <div className="space-y-2">
                <Label>Poll Interval</Label>
                <Select value={pollInterval} onValueChange={setPollInterval}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="3600">Hourly</SelectItem>
                    <SelectItem value="86400">Daily</SelectItem>
                    <SelectItem value="604800">Weekly</SelectItem>
                    <SelectItem value="2592000">Monthly</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label htmlFor="version_filter_include">Version Filter — Include (regex, optional)</Label>
                <Input
                  id="version_filter_include"
                  value={versionFilterInclude}
                  onChange={(e) => setVersionFilterInclude(e.target.value)}
                  placeholder='e.g. ^v\d+\.\d+\.\d+$'
                  className="font-mono text-sm"
                />
                <p className="text-xs text-muted-foreground">Only show/notify versions matching this pattern</p>
              </div>
              <div className="space-y-2">
                <Label htmlFor="version_filter_exclude">Version Filter — Exclude (regex, optional)</Label>
                <Input
                  id="version_filter_exclude"
                  value={versionFilterExclude}
                  onChange={(e) => setVersionFilterExclude(e.target.value)}
                  placeholder='e.g. -(alpha|beta|rc|nightly)'
                  className="font-mono text-sm"
                />
                <p className="text-xs text-muted-foreground">Hide/suppress versions matching this pattern</p>
              </div>
              {(provider === "github" || provider === "gitlab") && (
                <label className="flex items-center gap-2 text-sm text-muted-foreground">
                  <input
                    type="checkbox"
                    checked={excludePrereleases}
                    onChange={(e) => setExcludePrereleases(e.target.checked)}
                    className="rounded"
                  />
                  Exclude pre-releases
                </label>
              )}
            </div>
          )}
        </div>
      )}

      <div className="flex justify-end gap-2">
        <Button type="button" variant="outline" onClick={handleCancel}>Cancel</Button>
        <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
      </div>
    </form>
  );

  // Dialog mode: return form content without Card wrapper
  if (onSuccess) {
    return formContent;
  }

  // Page mode: wrap in Card
  return (
    <Card className="mx-auto max-w-2xl">
      <CardHeader>
        <CardTitle>{title}</CardTitle>
      </CardHeader>
      <CardContent>
        {formContent}
      </CardContent>
    </Card>
  );
}
